arguments.file_text:
namespace NotificationApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = "";
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 4;
    private readonly List<NotificationItem> _notifications = new()
    {
        new() { Id = 1, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-30) },
        new() { Id = 2, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-15) },
        new() { Id = 3, Message = "New feature available: dark mode.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
    };

    public Task<List<NotificationItem>> GetNotificationsAsync()
    {
        lock (_notifications)
        {
            return Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());
        }
    }

    public Task<List<NotificationItem>> GetNotificationsSinceAsync(int lastId)
    {
        // Simulate new notifications appearing over time
        lock (_notifications)
        {
            if (Random.Shared.Next(3) == 0) // ~33% chance each poll
            {
                var item = new NotificationItem
                {
                    Id = _nextId++,
                    Message = $"New event at {DateTime.UtcNow:HH:mm:ss}",
                    Timestamp = DateTime.UtcNow,
                };
                _notifications.Add(item);
            }

            return Task.FromResult(
                _notifications.Where(n => n.Id > lastId)
                              .OrderByDescending(n => n.Timestamp)
                              .ToList());
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationApp.Services
@inject NotificationService Svc
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (Items is not null)
    {
        <span class="badge">@Items.Count</span>
    }
</h1>

@if (Items is null)
{
    <p><em>Loading notifications…</em></p>
}
else if (Items.Count == 0)
{
    <p>No notifications.</p>
}
else
{
    <ul class="notification-list">
        @foreach (var n in Items)
        {
            <li>
                <span class="message">@n.Message</span>
                <span class="time">@n.Timestamp.ToString("HH:mm:ss")</span>
            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<NotificationItem>? Items { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures we only fetch when state wasn't restored from prerender
        Items ??= await Svc.GetNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender never runs during prerender — safe to start polling
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                var lastId = Items?.Max(n => n.Id) ?? 0;
                var newer = await Svc.GetNotificationsSinceAsync(lastId);

                if (newer.Count > 0)
                {
                    Items = newer.Concat(Items ?? []).ToList();
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public ValueTask DisposeAsync()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        return ValueTask.CompletedTask;
    }
}

h1 {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.badge {
    background: #0d6efd;
    color: white;
    border-radius: 999px;
    padding: 0.15em 0.6em;
    font-size: 0.55em;
    vertical-align: middle;
}

.notification-list {
    list-style: none;
    padding: 0;
}

.notification-list li {
    display: flex;
    justify-content: space-between;
    padding: 0.6rem 0;
    border-bottom: 1px solid #e0e0e0;
}

.time {
    color: #888;
    font-size: 0.85em;
    white-space: nowrap;
    margin-left: 1rem;
}

