+@page "/notifications"
+@rendermode InteractiveServer
+@using NotificationApp.Services
+@inject NotificationService Svc
+@implements IAsyncDisposable
+
+<PageTitle>Notifications</PageTitle>
+
+<h1>
+    Notifications
+    @if (Items is not null)
+    {
+        <span class="badge">@Items.Count</span>
+    }
+</h1>
+
+@if (Items is null)
+{
+    <p><em>Loading notifications…</em></p>
+}
+else if (Items.Count == 0)
+{
+    <p>No notifications.</p>
+}
+else
+{
+    <ul class="notification-list">
+        @foreach (var n in Items)
+        {
+            <li>
+                <span class="message">@n.Message</span>
+                <span class="time">@n.Timestamp.ToString("HH:mm:ss")</span>
+            </li>
+        }
+    </ul>
+}
+
+@code {
+    private CancellationTokenSource? _cts;
+
+    [PersistentState]
+    public List<NotificationItem>? Items { get; set; }
+
+    protected override async Task OnInitializedAsync()
+    {
+        // ??= ensures we only fetch when state wasn't restored from prerender
+        Items ??= await Svc.GetNotificationsAsync();
+    }
+
+    protected override void OnAfterRender(bool firstRender)
+    {
+        if (firstRender)
+        {
+            // OnAfterRender never runs during prerender — safe to start polling
+            _cts = new CancellationTokenSource();
+            _ = PollForNotificationsAsync(_cts.Token);
+        }
+    }
+
+    private async Task PollForNotificationsAsync(CancellationToken ct)
+    {
+        while (!ct.IsCancellationRequested)
+        {
+            try
+            {
+                await Task.Delay(TimeSpan.FromSeconds(5), ct);
+
+                var lastId = Items?.Max(n => n.Id) ?? 0;
+                var newer = await Svc.GetNotificationsSinceAsync(lastId);
+
+                if (newer.Count > 0)
+                {
+                    Items = newer.Concat(Items ?? []).ToList();
+                    await InvokeAsync(StateHasChanged);
+                }
+            }
+            catch (OperationCanceledException)
+            {
+                break;
+            }
+        }
+    }
+
+    public ValueTask DisposeAsync()
+    {
+        _cts?.Cancel();
+        _cts?.Dispose();
+        return ValueTask.CompletedTask;
