namespace NotificationApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = "";
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 4;
    private readonly List<NotificationItem> _notifications = new()
    {
        new() { Id = 1, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-30) },
        new() { Id = 2, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-15) },
        new() { Id = 3, Message = "New feature available: dark mode.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
    };

    public Task<List<NotificationItem>> GetNotificationsAsync()
    {
        lock (_notifications)
        {
            return Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());
        }
    }

    public Task<List<NotificationItem>> GetNotificationsSinceAsync(int lastId)
    {
        lock (_notifications)
        {
            // Simulate new notifications appearing over time (~33% chance each poll)
            if (Random.Shared.Next(3) == 0)
            {
                var item = new NotificationItem
                {
                    Id = _nextId++,
                    Message = $"New event at {DateTime.UtcNow:HH:mm:ss}",
                    Timestamp = DateTime.UtcNow,
                };
                _notifications.Add(item);
            }

            return Task.FromResult(
                _notifications.Where(n => n.Id > lastId)
                              .OrderByDescending(n => n.Timestamp)
                              .ToList());
        }
    }
}

